def parse_nombre(raw):
    toks = raw.split()
    if len(toks) < 3:
        return {'raw': raw, 'status': 'review', 'given': None, 'apellidos': None}
    return {
        'raw': raw,
        'status': 'ok',
        'given': ' '.join(toks[:-2]),
        'apellidos': toks[-2:],
    }
for s in ['Ana Quispe', 'Ana María Quispe Huamán', 'Solo']:
    print(parse_nombre(s))

