def normalize_email(raw):
    s = raw.strip().casefold()
    if s.count('@') != 1:
        raise ValueError(f"email debe tener un @: {raw!r}")
    if ' ' in s:
        raise ValueError(f"email con espacios: {raw!r}")
    local, domain = s.split('@')
    if not local or not domain:
        raise ValueError(f"local/dominio vacíos: {raw!r}")
    return s
print(normalize_email('  A@B.COM '))
for bad in ['@b.com', 'a@', 'a b@c.com']:
    try:
        normalize_email(bad)
    except ValueError as e:
        print('err', e)

